class Solution {
public:
    int leastOpsExpressTarget(int x, int target) {
        if (target == x) return 0;
        if (target < x) return 2;
        int res = 0, t = target;
        for (int d = 2; d <= t / d; ++d) {
            if (t % d == 0) {
                int c = 0;
                for (long long y = x; y <= t; y *= d) {
                    c++;
                    if (y == t) {
                        res = c + (c - 1);
                        break;
                    }
                }
                if (res) break;
            }
        }
        if (!res) res = (int)log2(t) + (t + x - 1) / x + 1;
        return res;
    }
};
